// PXCImage is one built image's installable Percona XtraDB Cluster versions,
// keyed by major series — drives the PXC frame's OS/version pickers.
type PXCImage struct {
	OS        string              `json:"os"`
	OSVersion string              `json:"osVersion"`
	Arch      string              `json:"arch"`
	Platform  string              `json:"platform"`
	Versions  map[string][]string `json:"versions"` // "8.0" → [...], "8.4" → [...]
}

// loadPXCCatalog / loadProxySQLCatalog / loadPSCatalog / loadPSMDBCatalog parse the
// per-image `percona_xtradb_cluster` / `proxysql` / `percona_server` /
// `percona_server_mongodb` sections of versions.yaml.
func loadPXCCatalog() []PXCImage      { return loadImageCatalog("percona_xtradb_cluster") }
func loadProxySQLCatalog() []PXCImage { return loadImageCatalog("proxysql") }
func loadPSCatalog() []PXCImage       { return loadImageCatalog("percona_server") }
func loadPSMDBCatalog() []PXCImage    { return loadImageCatalog("percona_server_mongodb") }
func loadPPGCatalog() []PXCImage      { return loadImageCatalog("percona_postgresql") }

// loadSpockCatalog returns the Spock (source-built PostgreSQL) availability:
// which PG majors/minors and OS/platforms Spock can be deployed on. Unlike the
// PPG catalog (Percona packages), this comes from the `spock:` section that
// `make versions` derives from the Spock patch set + postgresql.org release tags,
// and is populated only for Oracle Linux images (Spock compiles on RHEL only).
func loadSpockCatalog() []PXCImage { return loadImageCatalog("spock") }

// loadImagesCatalog returns every built image with its os/version/arch/platform
// but without any version map — used by nodes that only need the OS matrix
// (e.g. HAProxy), where the per-product catalogs would drop images that have an
// empty version map for that product.
func loadImagesCatalog() []PXCImage { return loadImageCatalog("") }

// loadImageCatalog parses the per-image `<wantSection>` major-series map of
// versions.yaml (each image's installable versions keyed by series). It mirrors
// the YAML the generator emits. Never errors — returns nil on any problem.
func loadImageCatalog(wantSection string) []PXCImage {
	path := versionsFilePath()
	if path == "" {
		return nil
	}
	f, err := os.Open(path)
	if err != nil {
		return nil
	}
	defer f.Close()

	var out []PXCImage
	var cur *PXCImage
	inImages := false
	inWanted := false // inside the requested per-image section
	series := ""      // current major series key while reading its list

	flush := func() {
		if cur != nil {
			out = append(out, *cur)
			cur = nil
		}
	}

	sc := bufio.NewScanner(f)
	sc.Buffer(make([]byte, 0, 64*1024), 1024*1024)
	for sc.Scan() {
		line := sc.Text()
		trimmed := strings.TrimSpace(line)
		if trimmed == "" || strings.HasPrefix(trimmed, "#") {
			continue
		}
		// Top-level key (no indent) — ends any image and the images block.
		if !strings.HasPrefix(line, " ") {
			flush()
			inImages = strings.HasPrefix(line, "images:")
			inWanted, series = false, ""
			continue
		}
		if !inImages {
			continue
		}
		// New image entry.
		if strings.HasPrefix(line, "  - os:") {
			flush()
			cur = &PXCImage{Versions: map[string][]string{}}
			cur.OS = unquoteYAML(strings.TrimSpace(strings.TrimPrefix(line, "  - os:")))
			inWanted, series = false, ""
			continue
		}
		if cur == nil {
			continue
		}
		// 4-space entry key / section header.
		if strings.HasPrefix(line, "    ") && !strings.HasPrefix(line, "      ") {
			inWanted, series = false, ""
			key, val := splitYAMLKV(trimmed)
			switch key {
			case "version":
				cur.OSVersion = val
			case "arch":
				cur.Arch = val
			case "platform":
				cur.Platform = val
			case wantSection:
				inWanted = true
			}
			continue
		}
		// 6-space major-series key under a section.
		if strings.HasPrefix(line, "      ") && !strings.HasPrefix(line, "        ") {
			if !inWanted {
				series = ""
				continue
			}
			key, val := splitYAMLKV(trimmed)
			series = unquoteYAML(key) // keys like "8.0" / "2" are quoted in the YAML
			if val == "[]" {
				cur.Versions[series] = []string{}
				series = ""
			} else if _, ok := cur.Versions[series]; !ok {
				cur.Versions[series] = []string{}
			}
			continue
		}
		// 8-space list item under the current series.
		if strings.HasPrefix(line, "        - ") {
			if inWanted && series != "" {
				v := unquoteYAML(strings.TrimSpace(strings.TrimPrefix(trimmed, "-")))
				if v != "" {
					cur.Versions[series] = append(cur.Versions[series], v)
				}
			}
		}
	}
	flush()
	return out
}

func (a *App) handlePXCCatalog(w http.ResponseWriter, r *http.Request) {
	if _, ok := a.currentUser(r); !ok {
		writeErr(w, http.StatusUnauthorized, "authentication required")
		return
	}
	writeJSON(w, http.StatusOK, map[string]any{"images": loadPXCCatalog()})
}

